// frontend/src/components/common/Navbar.js
import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import './Navbar.css';

const Navbar = () => {
    const { user, isAuthenticated, logout } = useAuth();
    const navigate = useNavigate();
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const dropdownRef = useRef(null);
    const buttonRef = useRef(null);

    const handleLogout = () => {
        logout();
        navigate('/');
        setMobileMenuOpen(false);
        setDropdownOpen(false);
    };

    const getDashboardLink = () => {
        if (!user) return '/';
        switch (user.user_type) {
            case 'worker': return '/dashboard';
            case 'client': return '/dashboard';
            case 'admin': return '/admin';
            default: return '/';
        }
    };

    const getProfileLink = () => {
        if (!user) return '/';
        if (user.user_type === 'worker') {
            return `/workers/${user.id}`;
        }
        return '/profile';
    };

    // Close dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (
                dropdownRef.current && 
                !dropdownRef.current.contains(event.target) &&
                buttonRef.current && 
                !buttonRef.current.contains(event.target)
            ) {
                setDropdownOpen(false);
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    // Toggle dropdown
    const toggleDropdown = () => {
        setDropdownOpen(!dropdownOpen);
    };

    return (
        <>
            <nav className="navbar">
                <div className="nav-container">
                    {/* Logo */}
                    <Link to="/" className="logo" onClick={() => setDropdownOpen(false)}>
                        <span className="logo-icon">🏠</span>
                        <span className="logo-text">Ekasilody</span>
                    </Link>

                    {/* Desktop Navigation Links */}
                    <div className="nav-links">
                        <Link to="/jobs" onClick={() => setDropdownOpen(false)}>Find Work</Link>
                        <Link to="/jobs/post" onClick={() => setDropdownOpen(false)}>Post Job</Link>
                        <Link to="/vouchers/buy" onClick={() => setDropdownOpen(false)}>Vouchers</Link>
                        {isAuthenticated && (
                            <Link to={getDashboardLink()} onClick={() => setDropdownOpen(false)}>Dashboard</Link>
                        )}
                    </div>

                    {/* Desktop Auth Buttons / User Menu */}
                    <div className="nav-buttons">
                        {isAuthenticated ? (
                            <div className="user-menu">
                                <button 
                                    ref={buttonRef}
                                    className="user-button"
                                    onClick={toggleDropdown}
                                    aria-expanded={dropdownOpen}
                                    aria-haspopup="true"
                                >
                                    <span className="user-avatar">
                                        {user?.name?.charAt(0) || 'U'}
                                    </span>
                                    <span className="user-name">
                                        {user?.name?.split(' ')[0]}
                                    </span>
                                    <span className={`dropdown-icon ${dropdownOpen ? 'open' : ''}`}>
                                        ▼
                                    </span>
                                </button>

                                {dropdownOpen && (
                                    <div ref={dropdownRef} className="dropdown-menu show">
                                        <div className="dropdown-header">
                                            <span className="user-type">{user?.user_type}</span>
                                            <span className="user-email">{user?.phone}</span>
                                        </div>
                                        <Link 
                                            to={getDashboardLink()} 
                                            className="dropdown-item"
                                            onClick={() => setDropdownOpen(false)}
                                        >
                                            📊 Dashboard
                                        </Link>
                                        <Link 
                                            to={getProfileLink()} 
                                            className="dropdown-item"
                                            onClick={() => setDropdownOpen(false)}
                                        >
                                            👤 My Profile
                                        </Link>
                                        <Link 
                                            to="/vouchers/my" 
                                            className="dropdown-item"
                                            onClick={() => setDropdownOpen(false)}
                                        >
                                            🎫 My Vouchers
                                        </Link>
                                        {user?.user_type === 'worker' && (
                                            <Link 
                                                to="/applications" 
                                                className="dropdown-item"
                                                onClick={() => setDropdownOpen(false)}
                                            >
                                                📋 My Applications
                                            </Link>
                                        )}
                                        <div className="dropdown-divider"></div>
                                        <button 
                                            onClick={handleLogout} 
                                            className="dropdown-item logout-btn"
                                        >
                                            🚪 Logout
                                        </button>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <>
                                <Link to="/login" className="btn-outline" onClick={() => setDropdownOpen(false)}>Sign In</Link>
                                <Link to="/register" className="btn-primary" onClick={() => setDropdownOpen(false)}>Join Now</Link>
                            </>
                        )}
                    </div>

                    {/* Mobile Menu Button */}
                    <button 
                        className="mobile-menu-button"
                        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                        aria-label="Toggle menu"
                    >
                        ☰
                    </button>
                </div>
            </nav>

            {/* Mobile Menu */}
            <div className={`mobile-menu ${mobileMenuOpen ? 'open' : ''}`}>
                <div className="mobile-menu-header">
                    <Link to="/" className="logo" onClick={() => setMobileMenuOpen(false)}>
                        <span className="logo-icon">🏠</span>
                        <span className="logo-text">Ekasilody</span>
                    </Link>
                    <button 
                        className="close-button"
                        onClick={() => setMobileMenuOpen(false)}
                        aria-label="Close menu"
                    >
                        ✕
                    </button>
                </div>

                <div className="mobile-nav-links">
                    <Link to="/jobs" onClick={() => setMobileMenuOpen(false)}>Find Work</Link>
                    <Link to="/jobs/post" onClick={() => setMobileMenuOpen(false)}>Post Job</Link>
                    <Link to="/vouchers/buy" onClick={() => setMobileMenuOpen(false)}>Buy Vouchers</Link>

                    {isAuthenticated && (
                        <>
                            <Link to={getDashboardLink()} onClick={() => setMobileMenuOpen(false)}>
                                Dashboard
                            </Link>
                            <Link to={getProfileLink()} onClick={() => setMobileMenuOpen(false)}>
                                My Profile
                            </Link>
                            <Link to="/vouchers/my" onClick={() => setMobileMenuOpen(false)}>
                                My Vouchers
                            </Link>
                            {user?.user_type === 'worker' && (
                                <Link to="/applications" onClick={() => setMobileMenuOpen(false)}>
                                    My Applications
                                </Link>
                            )}
                        </>
                    )}
                </div>

                {!isAuthenticated ? (
                    <div className="mobile-buttons">
                        <Link to="/login" className="btn-outline" onClick={() => setMobileMenuOpen(false)}>
                            Sign In
                        </Link>
                        <Link to="/register" className="btn-primary" onClick={() => setMobileMenuOpen(false)}>
                            Join Now
                        </Link>
                    </div>
                ) : (
                    <div className="mobile-user-info">
                        <div className="mobile-user-name">{user?.name}</div>
                        <div className="mobile-user-type">{user?.user_type}</div>
                        <div className="mobile-buttons">
                            <button onClick={handleLogout} className="btn-outline">
                                Logout
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </>
    );
};

export default Navbar;
